import{_ as e,c as a,o as i,ag as l}from"./chunks/framework.DPDPlp3K.js";const b=JSON.parse('{"title":"各平台设置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduce/Config/liveconfig.md","filePath":"guide/introduce/Config/liveconfig.md","lastUpdated":1743666007000}'),o={name:"guide/introduce/Config/liveconfig.md"};function d(r,t,h,c,n,s){return i(),a("div",null,t[0]||(t[0]=[l('<h1 id="各平台设置" tabindex="-1">各平台设置 <a class="header-anchor" href="#各平台设置" aria-label="Permalink to &quot;各平台设置&quot;">​</a></h1><p>此页面记录各直播平台的独立配置项。以下配置均在 WebUI 的「空间配置」→「各平台设置」中修改。</p><hr><h2 id="哔哩哔哩" tabindex="-1">哔哩哔哩 <a class="header-anchor" href="#哔哩哔哩" aria-label="Permalink to &quot;哔哩哔哩&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>推荐值</th></tr></thead><tbody><tr><td>Cookie 文件 (<code>bili_cookie_file</code>)</td><td>选择已登录的 B站账号</td><td>必填</td></tr><tr><td>直播流协议 (<code>bili_protocol</code>)</td><td>HLS 流格式</td><td><code>hls_fmp4</code>（国内）/ <code>hls</code></td></tr><tr><td>直播主 API (<code>bili_liveapi</code>)</td><td>境外服务器录制时的反代地址</td><td>留空或填入反代地址</td></tr><tr><td>录制弹幕</td><td>是否录制直播弹幕</td><td>按需开启</td></tr></tbody></table><h3 id="国内机器" tabindex="-1">国内机器 <a class="header-anchor" href="#国内机器" aria-label="Permalink to &quot;国内机器&quot;">​</a></h3><ul><li>下载器使用 <code>streamlink</code></li><li>需要安装 FFmpeg</li><li>Cookie 文件必选</li><li>协议选 <code>hls_fmp4</code></li></ul><h3 id="境外机器" tabindex="-1">境外机器 <a class="header-anchor" href="#境外机器" aria-label="Permalink to &quot;境外机器&quot;">​</a></h3><ul><li>需要自备国内反代服务器</li><li>反代目标：<code>https://api.live.bilibili.com</code></li><li>反代成功后打开该地址应显示 B站 404 页面</li><li>将反代地址填入「直播主 API」</li><li>可使用宝塔、Nginx、Caddy 等工具搭建反代</li></ul><hr><h2 id="虎牙-斗鱼" tabindex="-1">虎牙 / 斗鱼 <a class="header-anchor" href="#虎牙-斗鱼" aria-label="Permalink to &quot;虎牙 / 斗鱼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>CDN 选项</td><td>如果视频频繁断流，尝试切换 CDN 线路</td></tr></tbody></table><p>可使用默认下载器 <code>stream-gears</code>，不需要额外安装 FFmpeg。</p><hr><h2 id="抖音" tabindex="-1">抖音 <a class="header-anchor" href="#抖音" aria-label="Permalink to &quot;抖音&quot;">​</a></h2><p>需配置 Cookie 才能使用主页链接或避免风控。</p><hr><h2 id="快手" tabindex="-1">快手 <a class="header-anchor" href="#快手" aria-label="Permalink to &quot;快手&quot;">​</a></h2><ul><li>需中国大陆 IPv4 家宽 IP</li><li>24 小时内单直播间最多 120 次检测请求</li><li>风控较为严格，暂无完美解决方案</li></ul><hr><h2 id="twitch" tabindex="-1">Twitch <a class="header-anchor" href="#twitch" aria-label="Permalink to &quot;Twitch&quot;">​</a></h2><ul><li>可配置登录信息以获取更高画质</li><li>推荐录制回放（VOD）而非直播流</li><li>支持弹幕录制</li></ul><hr><h2 id="youtube" tabindex="-1">YouTube <a class="header-anchor" href="#youtube" aria-label="Permalink to &quot;YouTube&quot;">​</a></h2><ul><li>可配置登录信息</li><li>推荐录制回放（VOD）</li><li>可配置回放下载日期范围</li></ul><hr><h2 id="其他平台" tabindex="-1">其他平台 <a class="header-anchor" href="#其他平台" aria-label="Permalink to &quot;其他平台&quot;">​</a></h2><p>大部分平台使用默认 <code>stream-gears</code> 下载器即可，无需额外配置。如有特殊需求，请在 <strong>biliup 社区</strong> 或 <a href="https://github.com/biliup/biliup/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 中反馈。</p>',28)]))}const p=e(o,[["render",d]]);export{b as __pageData,p as default};
